#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> void CV(vector<T> &v){vector<T> t;v.swap(t);}
typedef long long ll;const int N=5e5+10,NW=1e6+10,INF=0x3f3f3f3f;
vector<int> d[NW];inline void Init(){const int w=1e6;rep(1,w,i)for(int j=i;j<=w;j+=i)d[j].push_back(i);}
int a[N],n,mn[N],cnt[NW];ll ans;
inline int bndr(int l,int r,int k)//mn[l~r]第1个<k的位置 ,mn 单调递减 
{
	int mid;while(l<=r)mn[mid=(l+r)>>1]<k?r=mid-1:l=mid+1;return r+1;
}
inline int bndl(int l,int r,int k)//mn[l~r]第1个<k的位置 ,mn 单调递增
{
	int mid;while(l<=r)mn[mid=(l+r)>>1]<k?l=mid+1:r=mid-1;return l-1;
}
inline void work(int l,int r)
{
	
	if(l==r){++ans;return;}int mid=(l+r)>>1,pl,pr,mx,Mn;
	memset(mn+mid+1,0x3f,(r-mid)*sizeof(int));
	mn[mid+1]=a[mid+1];rep(mid+2,r,i)mn[i]=min(mn[i-1],a[i]);
	pr=mid+1;mx=~INF;Mn=INF;drep(mid,l,pl)
	{
		mx=max(mx,a[pl]);Mn=min(Mn,a[pl]);
		assert(mn[pr]<NW);
		while(pr<=r&&a[pr]<=mx)++cnt[mn[pr++]];
		for(int x:d[mx]){if(x>=Mn)break;ans+=cnt[x];}
		if(mx%Mn==0)ans+=(bndr(mid+1,pr-1,Mn)-mid-1);
	}
	rep(mid+1,r,i)cnt[mn[i]]=0;
	memset(mn+l,0x3f,(mid-l+1)*sizeof(int));
	mn[mid]=a[mid];drep(mid-1,l,i)mn[i]=min(mn[i+1],a[i]);
	pl=mid;mx=~INF;Mn=INF;rep(mid+1,r,pr)
	{
		mx=max(mx,a[pr]);Mn=min(Mn,a[pr]);
		assert(mn[pl]<NW);
		while(pl>=l&&a[pl]<mx)++cnt[mn[pl--]];
		for(int x:d[mx]){if(x>=Mn)break;ans+=cnt[x];}
		if(mx%Mn==0)ans+=(mid-bndl(pl+1,mid,Mn));
	}
	rep(l,mid,i)cnt[mn[i]]=0;
	work(l,mid);work(mid+1,r);return;
	
}
inline void Solve()
{
	n=read();rep(1,n,i)a[i]=read();
	ans=0;work(1,n);printf("%lld\n",ans);
}
int main()
{
	Init();
	int T=read();while(T--)Solve();
	return 0;
}
